def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        if ratio > 2:
            priorities[i] = ratio ** 5 - np.sqrt(ratio) + np.log1p(ratio) * 2
        elif 1 < ratio <= 2:
            base_score = 0
            for j in range(1, 8):
                factor = (-1) ** j * (ratio ** j) / (j + 1)
                if j % 3 == 0:
                    factor *= 1.5
                base_score += factor
            priorities[i] = abs(base_score) + np.exp(-ratio)
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            for j in range(1, 10):
                weight = (j % 4 + 1) * 0.3
                term = (ratio ** j) * weight / (j ** 1.5)
                if j % 2 == 0:
                    term *= 1.1
                else:
                    term *= 0.9
                score += term
            if bin_capacity < item * 1.2:
                score *= 2.5
                for k in range(1, 5):
                    score += (bin_capacity / (item * k)) ** 0.7 / (k + 2)
            elif bin_capacity < item * 2.5:
                score *= 1.7
                for k in range(1, 3):
                    score += np.log1p(bin_capacity / (item * k)) / (k + 1)
            else:
                for k in range(1, 6):
                    score += (bin_capacity / (item * k)) ** 0.4 / (k + 3)
            if score < 0:
                score = abs(score) * 0.5
            priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        min_priority = np.min(finite_priorities)
    else:
        max_priority = 1
        min_priority = 0
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 4
        elif priorities[i] < 0:
            priorities[i] = min_priority
        elif priorities[i] > max_priority:
            priorities[i] = max_priority
    return priorities
